+	trimmed := strings.TrimSpace(output)
+	if trimmed == "" {
+		return 0, errors.New("no values returned")
+	}
+
+	lines := strings.Split(trimmed, "\n")
+	minVal := 0
+	found := false
+	hasWindowOne := false
+
+	for _, line := range lines {
+		line = strings.TrimSpace(line)
+		if line == "" {
